const MINUTOS_LIMITE = 5;
const ahora = Date.now();
const limite = MINUTOS_LIMITE * 60 * 1000;

const conversations = $input.first().json.data || [];
const sinRespuesta = [];

for (const conv of conversations) {
  const mensajes = conv.messages?.data || [];
  if (mensajes.length === 0) continue;

  // El primer elemento es el más reciente
  const ultimoMsg = mensajes[0];
  const ultimoTiempo = new Date(ultimoMsg.created_time).getTime();
  const antiguedad = ahora - ultimoTiempo;

  // Solo nos interesan conversaciones donde el ÚLTIMO mensaje
  // es del CLIENTE (la página no ha respondido aún)
  const esDelCliente = String(ultimoMsg.from?.id) !== String(PAGE_ID);

  // Debug: lo puedes ver en el output para verificar
  console.log(`Conv: ${conv.id} | Último from: ${ultimoMsg.from?.id} | PAGE_ID: ${PAGE_ID} | esDelCliente: ${esDelCliente} | antigüedad: ${Math.floor(antiguedad/60000)} min`);

  if (esDelCliente && antiguedad >= limite) {
    const participantes = conv.participants?.data || [];
    const cliente = participantes.find(p => String(p.id) !== String(PAGE_ID));

    sinRespuesta.push({
      json: {
        conversation_id: conv.id,
        psid: cliente?.id,
        nombre: cliente?.name || 'Cliente',
        ultimo_mensaje: ultimoMsg.message,
        minutos_sin_respuesta: Math.floor(antiguedad / 60000)
      }
    });
  }
}

if (sinRespuesta.length === 0) return [{ json: { total: 0, skip: true } }];
return sinRespuesta;
